            nx, ny = sx + dx, sy + dy
            if not free(nx, ny):
                continue
            dres = min(cheb(nx, ny, rx, ry) for rx, ry in resources)
            dop = cheb(nx, ny, ox, oy)
            score = -dres * 100 + dop
            if best is None or score > best_score:
                best = [dx, dy]
                best_score = score
    else:
        cx, cy = (w - 1) / 2.0, (h - 1) / 2.0
        for dx, dy in dirs:
            nx, ny = sx + dx, sy + dy
            if not free(nx, ny):
                continue
            dcen = cheb(nx, ny, int(cx + 0.5), int(cy + 0.5))
            dop = cheb(nx, ny, ox, oy)
            score = -dcen * 100 + dop
            if best is None or score > best_score:
                best = [dx, dy]
                best_score = score

    if best is None:
        return [0, 0]
    return best
